export interface ExcavationEffect {
  createExcavationEffect?: { boundaryMm: { xMm: number; yMm: number }[]; depthMm: number };
  stillActive: boolean;
}

export function initialExcavationState(): ExcavationState {
  return { phase: 'idle', verticesMm: [] };
}

