105	const IDENTITY_T = ((key: string) => key) as unknown as TFunction;
106	
107	export function getAllCommandCapabilities(): CommandCapability[] {
108	  return [
109	    ...buildToolCapabilities(),
110	    ...NAVIGATION_CAPABILITIES,
111	    ...SYSTEM_CAPABILITIES,
112	    ...SCHEDULE_CAPABILITIES,
113	    ...SHEET_CAPABILITIES,
114	    ...SECTION_CAPABILITIES,
115	    ...VIEW_3D_CAPABILITIES,
116	    ...EDIT_3D_CAPABILITIES,
117	    ...VISIBILITY_CAPABILITIES,
118	  ];
119	}
