121	export function getCommandCapability(id: string): CommandCapability | undefined {
122	  return getAllCommandCapabilities().find((capability) => capability.id === id);
123	}
124	
125	export function capabilityIdForTool(toolId: ToolId): string {
126	  return `tool.${toolId}`;
127	}
128	
129	export function commandModeBadge(availability: CommandAvailability): string {
130	  if (availability.state === 'disabled') return 'Unavailable';
131	  if (availability.state === 'bridge') return formatCapabilityMode(availability.targetMode);
132	  if (availability.capability.scope === 'universal') return 'Universal';
133	  if (availability.capability.intendedModes.length === CAPABILITY_VIEW_MODES.length) {
134	    return 'Universal';
135	  }
136	  return availability.capability.intendedModes.map(formatCapabilityMode).join(' / ');
137	}
