139	export function evaluateCommandInMode(
140	  commandId: string,
141	  mode: CapabilityViewMode,
142	  lensMode: CapabilityLensMode = 'all',
143	): CommandAvailability | null {
144	  const capability = getCommandCapability(commandId);
145	  if (!capability) return null;
146	  if (capability.intendedModes.includes(mode)) {
147	    const lensDisabledReason = lensDisabledReasonForCommand(commandId, lensMode);
148	    if (lensDisabledReason) {
149	      return {
150	        state: 'disabled',
151	        capability,
152	        reason: lensDisabledReason,
153	      };
154	    }
155	    return { state: 'enabled', capability };
156	  }
157	  const targetMode = capability.bridgeToMode?.[mode];
158	  if (targetMode) {
159	    return {
160	      state: 'bridge',
161	      capability,
162	      targetMode,
163	      reason: `${capability.label} runs in ${formatCapabilityMode(targetMode)}, not ${formatCapabilityMode(mode)}.`,
164	    };
165	  }
166	  return {
167	    state: 'disabled',
168	    capability,
169	    reason: `${capability.label} is unavailable in ${formatCapabilityMode(mode)}.`,
170	  };
171	}
