219	function lensDisabledReasonForCommand(
220	  commandId: string,
221	  lensMode: CapabilityLensMode,
222	): string | undefined {
223	  if (lensMode !== 'structure' && lensMode !== 'mep') return undefined;
224	  const lensRules = LENS_DISABLED_COMMANDS[lensMode];
