229	export function auditCommandExposures(
230	  exposures: readonly CommandExposure[],
231	): CommandExposureViolation[] {
232	  const violations: CommandExposureViolation[] = [];
233	  for (const exposure of exposures) {
234	    const availability = evaluateCommandInMode(exposure.commandId, exposure.mode);
235	    if (!availability) {
236	      violations.push({
237	        exposure,
238	        expected: 'disabled',
239	        reason: `No capability is registered for ${exposure.commandId}.`,
240	      });
241	      continue;
242	    }
243	    if (availability.state === 'enabled') continue;
244	    if (availability.state === 'bridge' && exposure.behavior === 'bridge') continue;
245	    if (availability.state === 'disabled' && exposure.behavior === 'disabled') continue;
246	    violations.push({
247	      exposure,
248	      expected: availability.state,
249	      reason: availability.reason,
250	    });
251	  }
252	  return violations;
253	}
