308	    .split(/[-_]/g)
309	    .filter(Boolean)
310	    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
311	    .join(' ');
312	}
313	
314	function groupForTool(toolId: ToolId): CommandGroup {
315	  if (MODIFY_TOOL_IDS.has(toolId)) return 'modify';
316	  if (toolId === 'select' || toolId === 'query' || toolId === 'measure') return 'view';
317	  if (toolId === 'dimension' || toolId === 'tag') return 'document';
318	  return 'author';
319	}
320	
321	function executionSurfaceForTool(tool: ToolDefinition): ExecutionSurface {
322	  if (tool.modes.includes('sheet') || tool.modes.includes('schedule')) return 'canvas';
323	  return 'canvas';
324	}
325	
326	function preconditionsForTool(toolId: ToolId): string[] {
327	  switch (toolId) {
328	    case 'door':
329	    case 'window':
330	    case 'floor':
331	    case 'roof':
332	    case 'dimension':
333	      return ['has-wall'];
334	    case 'railing':
335	      return ['has-floor-or-wall'];
336	    case 'move':
337	    case 'copy':
338	    case 'rotate':
339	    case 'mirror':
340	    case 'align':
341	      return ['has-selection'];
342	    default:
343	      return [];
344	  }
345	}
346	
347	function bridgeModesForTool(
348	  tool: ToolDefinition,
349	): Partial<Record<CapabilityViewMode, CapabilityViewMode>> | undefined {
350	  if (!tool.modes.includes('plan')) return undefined;
351	  const bridge: Partial<Record<CapabilityViewMode, CapabilityViewMode>> = {};
352	  for (const mode of CAPABILITY_VIEW_MODES) {
353	    if (!tool.modes.includes(mode)) bridge[mode] = 'plan';
354	  }
355	  return Object.keys(bridge).length ? bridge : undefined;
356	}
