1	import { describe, expect, it } from 'vitest';
2	import { initialSteelConnectionState, reduceSteelConnection } from './toolGrammar';
3	
4	describe('reduceSteelConnection', () => {
5	  it('idle → pick-beam effect contains hostElementId', () => {
6	    const s = initialSteelConnectionState();
7	    const { effect } = reduceSteelConnection(s, { kind: 'pick-beam', hostElementId: 'beam-42' });
8	    expect(effect.createSteelConnection?.hostElementId).toBe('beam-42');
9	    expect(effect.createSteelConnection?.connectionType).toBe('end_plate');
10	    expect(effect.stillActive).toBe(true);
11	  });
12	
