2537	/* ────────────────────────────────────────────────────────────────────── */
2538	/* Steel Connection Tool — §9.5.1                                         */
2539	/* One click on a beam creates a connection at positionT=1.0 (end).       */
2540	/* ────────────────────────────────────────────────────────────────────── */
2541	
2542	export type SteelConnectionState = { phase: 'idle' };
2543	
2544	export type SteelConnectionEvent =
2545	  | { kind: 'activate' }
2546	  | { kind: 'deactivate' }
2547	  | { kind: 'pick-beam'; hostElementId: string }
2548	  | { kind: 'cancel' };
2549	
2550	export interface SteelConnectionEffect {
2551	  createSteelConnection?: {
2552	    hostElementId: string;
2553	    connectionType: 'end_plate' | 'bolted_flange' | 'shear_tab';
2554	  };
2555	  stillActive: boolean;
2556	}
2557	
2558	export function initialSteelConnectionState(): SteelConnectionState {
2559	  return { phase: 'idle' };
2560	}
2561	
2562	export function reduceSteelConnection(
2563	  state: SteelConnectionState,
2564	  event: SteelConnectionEvent,
2565	): { state: SteelConnectionState; effect: SteelConnectionEffect } {
2566	  if (event.kind === 'deactivate') {
2567	    return { state: initialSteelConnectionState(), effect: { stillActive: false } };
2568	  }
2569	  if (event.kind === 'activate' || event.kind === 'cancel') {
2570	    return {
2571	      state: initialSteelConnectionState(),
2572	      effect: { stillActive: event.kind === 'activate' },
2573	    };
2574	  }
2575	  if (event.kind === 'pick-beam') {
2576	    return {
2577	      state: initialSteelConnectionState(),
2578	      effect: {
2579	        createSteelConnection: {
2580	          hostElementId: event.hostElementId,
2581	          connectionType: 'end_plate',
2582	        },
2583	        stillActive: true,
2584	      },
2585	    };
2586	  }
2587	  return { state, effect: { stillActive: true } };
2588	}
